/* ── Room data ──────────────────────────────────────────────── */
const ROOMS={
  A:{name:"A 教室",price:300,size:"4.3×3.4 m｜約4.5坪",capacity:"5～13人",desc:"小型讀書會・精緻家教班",equipment:["移動式會議桌×5","皮製折疊椅×13","移動式直立白板","55吋4K電視螢幕"]},
  B:{name:"B 教室",price:200,size:"3.2×3.2 m｜約3坪",capacity:"4～6人",desc:"1對1或1對多私人家教",equipment:["鄉村風會議桌×2","皮製折疊椅×6","55吋4K電視螢幕"]},
  C:{name:"C 教室",price:400,size:"4.2×4.2 m｜約5.4坪",capacity:"12～17人",desc:"空間方正・各類小班課程",equipment:["移動式會議桌×5","皮製折疊椅×17","防眩光白板","55吋4K螢幕","無線麥克風×2"]},
  D:{name:"D 教室",price:600,size:"10.3×4 m｜約12.5坪",capacity:"18～30人",desc:"講座・說明會・訓練課程",equipment:["移動式會議桌×10","皮製折疊椅×30","65吋4K螢幕","固定55吋4K螢幕","杜比環繞音響","無線麥克風×2"]},
};

const TIME_OPTS=[];
for(let m=7*60;m<=23*60;m+=30) TIME_OPTS.push(`${String(Math.floor(m/60)).padStart(2,"0")}:${String(m%60).padStart(2,"0")}`);

function toMin(t){const[h,m]=t.split(":").map(Number);return h*60+m;}
function rawH(s,e){const d=toMin(e)-toMin(s);return d>0?d/60:0;}
function calcPrice(room,hours){
  const r=ROOMS[room];if(!r||hours<=0)return{total:0,bonus:0,effective:0,charged:0};
  if(hours>=10)return{total:r.price*10,bonus:0,effective:10,charged:10};
  const full=Math.floor(hours),half=hours%1>=0.5?0.5:0;
  const charged=full+half,bonus=Math.floor(full/3);
  return{total:charged*r.price,bonus,effective:charged+bonus,charged};
}

const TABS=[{id:"教室介紹",icon:"🏫"},{id:"立即預約",icon:"📅"},{id:"管理後台",icon:"🔐"}];
const INIT={room:"A",date:"",startTime:"09:00",endTime:"10:00",name:"",phone:"",note:""};
const LOGO_SRC="data:image/jpeg;base64,";

